def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, 8):
                inner_score = ((1 - ratio) ** (a * 1.1)) * (a * 0.9)
                if inner_score > 3:
                    inner_score /= (a + 1.5)
                if a % 3 == 0:
                    inner_score *= 0.8
                elif a % 2 == 0:
                    inner_score *= 0.9
                else:
                    inner_score *= 1.2
                score += inner_score
            if (capacity + item) % 5 == 0:
                score *= 0.9
            if score > 7:
                score /= 3.5
            for extra_check in range(1, 4):
                if abs(capacity - item * extra_check) < 1.5:
                    score += extra_check * 0.7
        elif 0.2 <= ratio < 0.4:
            fact = 1
            limit = int(capacity // 1.8) + 2
            for n in range(2, limit):
                fact *= n
                if fact > 1e6:
                    fact %= 2000
                    break
            mod_fact = fact % 600
            score += np.log1p(ratio * mod_fact) * 1.2
            if (int(capacity) % 3 == 0) and (item % 0.2 == 0):
                score += 4
            else:
                score -= 0.3
            extra = 0
            for x in range(1, 6):
                frac_part = ((ratio * x * 1.1) % 1)
                extra += frac_part * (x ** 1.7)
            score += extra / 5
            if capacity > 40 and score < 0:
                score += 3
        elif 0.4 <= ratio <= 0.7:
            for m in range(1, 6):
                increment = (ratio ** (m + 2)) * (m ** 3.5) / (m + 1.3)
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 7 + remainder * 0.8
            else:
                score -= remainder * 0.8
            if score < 0:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 7 == 0:
                score *= 1.15
            if capacity > 60 and ratio > 0.6:
                score *= 1.05
        elif 0.7 < ratio <= 1.1:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.7) ** p) * (p ** 1.3)
            score = base_penalty * 12
            if capacity < item * 1.05:
                score += 12
            if (int(capacity * 12) % 5 == 0) and (int(item * 15) % 7 == 0):
                score -= 5
            if score < 0:
                score *= -1.1
                score += 3
            for adj in range(1, 4):
                if (capacity + item * adj) % 6 == 0:
                    score -= adj * 0.7
                else:
                    score += adj * 0.4
        else:
            penalty = 0
            diff = ratio - 1.1
            for q in range(1, 12):
                penalty += ((diff) ** q) * (q ** 2.5)
            score = penalty * 18
            if capacity < item * 1.4:
                score += 15
            if (int(capacity * 9) % 4 == 0) and (int(item * 13) % 3 == 0):
                score -= 7
            for z in range(2, 6):
                score += ((diff / z) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.5
            skip_inc = 0
            for c in range(1, 5):
                if (int(capacity * c) + int(item * c)) % 10 == 0:
                    skip_inc += c * 0.6
            score += skip_inc
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.2)
        elif capacity < 10:
            score *= 2.2
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q75 = np.percentile(finite_priorities, 75)
        top_ratio_count = np.sum(finite_priorities > q75)
        fill_value = np.max(finite_priorities) * (15 + top_ratio_count)
    priorities[np.isinf(priorities)] = fill_value
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val
    for idx in range(len(priorities)):
        if priorities[idx] < 0:
            priorities[idx] *= 1.1
        elif priorities[idx] > 0:
            priorities[idx] *= 0.9
        if i % 3 == 0:
            priorities[idx] += (idx % 4) * 0.3
    return priorities
